const SPEC_SCHEMA = {"type": "object", "additionalProperties": false, "required": ["target", "edits", "overall_plan"], "properties": {"target": {"type": "string"}, "overall_plan": {"type": "string"}, "edits": {"type": "array", "maxItems": 40, "items": {"type": "object", "additionalProperties": false, "required": ["addresses", "locator", "action", "instruction"], "properties": {"addresses": {"type": "string", "description": "which deficit(s) this edit resolves"}, "locator": {"type": "string", "description": "unique anchor text in the file to find the edit site"}, "action": {"type": "string", "enum": ["replace", "insert-after", "insert-before", "rewrite-section"]}, "instruction": {"type": "string", "description": "exactly what the drafting agent must write, including corrected values/code verbatim where known"}, "corrected_value": {"type": "string", "description": "for correctness-bugs: the right number/formula/code, fully worked out"}, "is_bug_fix": {"type": "boolean"}}}}}}
const VERIFY_SCHEMA = {"type": "object", "additionalProperties": false, "required": ["target", "passed", "deficits_resolved", "deficits_unresolved", "new_problems", "notes"], "properties": {"target": {"type": "string"}, "passed": {"type": "boolean", "description": "true only if all deficits resolved AND no new problems AND build-safe"}, "deficits_resolved": {"type": "integer"}, "deficits_unresolved": {"type": "array", "items": {"type": "string"}}, "new_problems": {"type": "array", "items": {"type": "string"}}, "build_safe": {"type": "boolean", "description": "figure markers/admonitions/links intact, code fences balanced"}, "notes": {"type": "string"}}}

// Reasoning on Opus 4.8; drafting on Sonnet 5 (user routing 2026-07-20).
const results = await pipeline(
  WORK,
  // Stage 1: SPEC (Opus)
  w => agent(w.spec, { label: `spec:${w.target}`, phase: 'Spec', schema: SPEC_SCHEMA,
                       model: 'opus', effort: 'high' })
        .then(spec => ({ w, spec })),
  // Stage 2: APPLY (Sonnet 5) — gets the spec inline
  ({ w, spec }) => agent(
     w.apply + "\n\n## EDIT SPEC (apply every edit)\n" + JSON.stringify(spec, null, 2),
     { label: `apply:${w.target}`, phase: 'Apply', model: 'claude-sonnet-5' })
     .then(applied => ({ w, applied })),
  // Stage 3: VERIFY (Opus)
  ({ w }) => agent(w.verify, { label: `verify:${w.target}`, phase: 'Verify',
                                  schema: VERIFY_SCHEMA, model: 'opus', effort: 'high' })
                .then(v => ({ target: w.target, n_critical: w.n_critical, verdict: v })),
)

const done = results.filter(Boolean)
const passed = done.filter(r => r.verdict && r.verdict.passed).map(r => r.target)
const failed = done.filter(r => !r.verdict || !r.verdict.passed)
                   .map(r => ({ target: r.target, unresolved: r.verdict?.deficits_unresolved,
                                new_problems: r.verdict?.new_problems }))
const died = WORK.filter((w, i) => !results[i]).map(w => w.target)

log(`revised ${done.length}/${WORK.length} | passed ${passed.length} | failed ${failed.length} | died ${died.length}`)
log(`PASSED (append to revise_done.txt): ${passed.join(' ')}`)
if (failed.length) log(`FAILED (needs another pass): ${failed.map(f => f.target).join(' ')}`)
if (died.length) log(`DIED (re-run to resume): ${died.join(' ')}`)

return { passed, failed, died }
